package main

import (
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"io"
	"log"
	"mime/multipart"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

const (
	uploadDir    = "./public/uploads"
	maxUploadSize = 10 << 20 // 10 MB
)

// allowedExtensions maps allowed file extensions to their expected MIME type prefixes
var allowedExtensions = map[string][]string{
	// Images
	".jpg":  {"image/jpeg"},
	".jpeg": {"image/jpeg"},
	".png":  {"image/png"},
	".gif":  {"image/gif"},
	".webp": {"image/webp"},
	".svg":  {"image/svg+xml"},
	".bmp":  {"image/bmp"},
	// Documents
	".pdf":  {"application/pdf"},
	".doc":  {"application/msword"},
	".docx": {"application/vnd.openxmlformats-officedocument.wordprocessingml.document"},
	".xls":  {"application/vnd.ms-excel"},
	".xlsx": {"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"},
	".ppt":  {"application/vnd.ms-powerpoint"},
	".pptx": {"application/vnd.openxmlformats-officedocument.presentationml.presentation"},
	".txt":  {"text/plain"},
	".csv":  {"text/csv", "text/plain", "application/csv"},
	".rtf":  {"application/rtf", "text/rtf"},
	// Archives
	".zip": {"application/zip", "application/x-zip-compressed"},
	".tar": {"application/x-tar"},
	".gz":  {"application/gzip", "application/x-gzip"},
	".rar": {"application/vnd.rar", "application/x-rar-compressed"},
	".7z":  {"application/x-7z-compressed"},
}

func main() {
	if err := os.MkdirAll(uploadDir, 0755); err != nil {
		log.Fatalf("Failed to create upload directory: %v", err)
	}

	mux := http.NewServeMux()
	mux.HandleFunc("/upload", uploadHandler)
	mux.Handle("/public/", http.StripPrefix("/public/", http.FileServer(http.Dir("./public"))))

	fmt.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", mux))
}

func uploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, maxUploadSize)

	if err := r.ParseMultipartForm(maxUploadSize); err != nil {
		http.Error(w, "File too large or invalid form data", http.StatusBadRequest)
		return
	}
	defer r.MultipartForm.RemoveAll()

	file, header, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Failed to read uploaded file", http.StatusBadRequest)
		return
	}
	defer file.Close()

	// Validate the file
	safeFilename, err := validateAndSanitizeFile(file, header)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	// Generate a unique filename to prevent overwrites and enumeration
	uniqueName, err := generateUniqueFilename(safeFilename)
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	destPath := filepath.Join(uploadDir, uniqueName)

	// Ensure the resolved path is still within the upload directory (prevent path traversal)
	absDestPath, err := filepath.Abs(destPath)
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}
	absUploadDir, err := filepath.Abs(uploadDir)
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}
	if !strings.HasPrefix(absDestPath, absUploadDir+string(os.PathSeparator)) {
		http.Error(w, "Invalid file path", http.StatusBadRequest)
		return
	}

	dst, err := os.OpenFile(absDestPath, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0644)
	if err != nil {
		http.Error(w, "Failed to save file", http.StatusInternalServerError)
		return
	}
	defer dst.Close()

	// Reset file reader position after content type detection
	if seeker, ok := file.(io.Seeker); ok {
		seeker.Seek(0, io.SeekStart)
	}

	if _, err := io.Copy(dst, file); err != nil {
		// Clean up partial file
		os.Remove(absDestPath)
		http.Error(w, "Failed to save file", http.StatusInternalServerError)
		return
	}

	publicPath := "/public/uploads/" + uniqueName

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, `{"path": %q, "filename": %q, "size": %d}`, publicPath, header.Filename, header.Size)
}

func validateAndSanitizeFile(file multipart.File, header *multipart.FileHeader) (string, error) {
	// Get and validate extension
	originalName := filepath.Base(header.Filename)
	ext := strings.ToLower(filepath.Ext(originalName))

	if ext == "" {
		return "", fmt.Errorf("file must have an extension")
	}

	allowedMIMEs, ok := allowedExtensions[ext]
	if !ok {
		return "", fmt.Errorf("file type %q is not allowed", ext)
	}

	// Read the first 512 bytes to detect content type
	buf := make([]byte, 512)
	n, err := file.Read(buf)
	if err != nil && err != io.EOF {
		return "", fmt.Errorf("failed to read file content")
	}
	buf = buf[:n]

	detectedType := http.DetectContentType(buf)

	// Verify detected MIME type matches expected types for the extension
	if !isMIMEAllowed(detectedType, allowedMIMEs) {
		return "", fmt.Errorf("file content does not match extension (detected: %s)", detectedType)
	}

	// Reset file position
	if seeker, ok := file.(io.Seeker); ok {
		if _, err := seeker.Seek(0, io.SeekStart); err != nil {
			return "", fmt.Errorf("failed to reset file reader")
		}
	}

	// Sanitize filename: only keep alphanumeric, hyphens, underscores, and dots
	baseName := strings.TrimSuffix(originalName, ext)
	sanitized := sanitizeFilename(baseName)
	if sanitized == "" {
		sanitized = "file"
	}

	return sanitized + ext, nil
}

func isMIMEAllowed(detected string, allowed []string) bool {
	// http.DetectContentType returns types like "application/octet-stream" for many binary formats
	// We accept octet-stream as a fallback for binary document/archive types
	if detected == "application/octet-stream" {
		return true
	}

	for _, mime := range allowed {
		if strings.EqualFold(detected, mime) {
			return true
		}
	}

	// For text-based types, DetectContentType might return "text/plain; charset=utf-8"
	detectedBase := strings.Split(detected, ";")[0]
	detectedBase = strings.TrimSpace(detectedBase)
	for _, mime := range allowed {
		if strings.EqualFold(detectedBase, mime) {
			return true
		}
	}

	return false
}

func sanitizeFilename(name string) string {
	var builder strings.Builder
	for _, r := range name {
		if (r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || r == '-' || r == '_' {
			builder.WriteRune(r)
		}
	}
	result := builder.String()
	// Limit length
	if len(result) > 100 {
		result = result[:100]
	}
	return result
}

func generateUniqueFilename(sanitizedName string) (string, error) {
	randomBytes := make([]byte, 16)
	if _, err := rand.Read(randomBytes); err != nil {
		return "", err
	}
	randomHex := hex.EncodeToString(randomBytes)

	ext := filepath.Ext(sanitizedName)
	base := strings.TrimSuffix(sanitizedName, ext)

	return fmt.Sprintf("%s_%s%s", base, randomHex, ext), nil
}